script.text:
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {f.add_onResponseComplete(on$Filter$ResponseComplete);}
function close$VoucherFilter$(sender) {try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, s = '';
      g._period = f.getItem('ky').value, g._year = f.getItem('nam').value;
      g._unit = f.getItem('ma_dvcs').value;
      g._alterTitle = [null, [['%p', g._period, true], ['%y', g._year, true]]];
      if (g._$k != null) g._$k = [];
      if (g._$u != null) g._$u = [];
      break;
    default:
      break;
  }
}
/* </flatten> */
